int starting_col[ 7 ] = { 0 , 4 , 0 , 2 , 0 , 1 , 0 };
int row_increment[ 7 ] = { 8 , 8 , 8 , 4 , 4 , 2 , 2 };
int col_increment[ 7 ] = { 8 , 8 , 4 , 4 , 2 , 2 , 1 };
